const __dirname = fileURLToPath(new URL('.', import.meta.url));
const PORT = 19000 + Math.floor(Math.random() * 1000);
const DB_PATH = join(__dirname, 'app.db');
let _uid = 0;
function uid(p) { return p + '_' + (++_uid); }

async function api(method, path, body) {
  const opts = { method, headers: { 'Content-Type': 'application/json' } };
  if (body) opts.body = JSON.stringify(body);
  const res = await fetch(`http://localhost:${PORT}${path}`, opts);
  const data = await res.json().catch(() => null);
  return { status: res.status, data };
}

let serverProc;

before(async () => {
  if (existsSync(DB_PATH)) unlinkSync(DB_PATH);
  serverProc = spawn('node', [join(__dirname, 'server.js')], {
    env: { ...process.env, PORT: String(PORT) },
    stdio: ['pipe', 'pipe', 'pipe']
  });
  await new Promise((resolve, reject) => {
    const timeout = setTimeout(() => reject(new Error('Server start timeout')), 5000);
    serverProc.stdout.on('data', (d) => {
      if (d.toString().includes('wake server')) { clearTimeout(timeout); resolve(); }
    });
  });
});

after(() => {
  serverProc.kill();
  if (existsSync(DB_PATH)) unlinkSync(DB_PATH);
});

function buildContact(o = {}) { return { 'name': uid('name'), 'email': uid('email'), 'company': uid('company'), ...o }; }
function buildNote(o = {}) { return { 'content': uid('content'), 'created-at': uid('created-at'), ...o }; }
async function createContact(overrides = {}) {
  const o = buildContact(overrides);
  const { data } = await api('POST', '/api/contacts', o);
  return data;
}
async function createNote(overrides = {}) {
  const o = buildNote(overrides);
  if (!o['contact']) { const p = await createContact(); o['contact'] = Number(p.eid); }
  const { data } = await api('POST', '/api/notes', o);
  return data;
}

