describe('contact constraints', () => {
  it('rejects duplicate email', async () => {
    const dup = uid('dup');
    await createContact({ 'email': dup });
    const { status } = await api('POST', '/api/contacts', buildContact({ 'email': dup }));
    assert.ok(status >= 400);
  });

  it('survives SQL injection in name', async () => {
    const e = await createContact({ 'name': "'; DROP TABLE contact; --" });
    assert.ok(e.eid);
    const { data } = await api('GET', '/api/contacts');
    assert.ok(Array.isArray(data));
  });

  it('rejects bogus status value', async () => {
    const e = await createContact();
    const { status } = await api('PUT', `/api/contacts/${e.eid}`, { status: 'NONEXISTENT' });
    assert.equal(status, 400);
  });

  it('ignores unknown fields in PUT', async () => {
    const e = await createContact();
    const { status, data } = await api('PUT', `/api/contacts/${e.eid}`, { __hack__: 'x' });
    assert.equal(status, 400);
  });

});

