describe('ContactStatus transitions', () => {
  it('defaults to active', async () => {
    const e = await createContact();
    assert.equal(e.status, 'active');
  });

  it('active → inactive succeeds', async () => {
    const created = await createContact();
    const { status } = await api('PUT', `/api/contacts/${created.eid}`, { status: 'inactive' });
    assert.equal(status, 200);
  });

  it('active → archived succeeds', async () => {
    const created = await createContact();
    const { status } = await api('PUT', `/api/contacts/${created.eid}`, { status: 'archived' });
    assert.equal(status, 200);
  });

  it('inactive → active succeeds', async () => {
    const created = await createContact();
    await api('PUT', `/api/contacts/${created.eid}`, { status: 'inactive' });
    const { status } = await api('PUT', `/api/contacts/${created.eid}`, { status: 'active' });
    assert.equal(status, 200);
  });

  it('inactive → archived succeeds', async () => {
    const created = await createContact();
    await api('PUT', `/api/contacts/${created.eid}`, { status: 'inactive' });
    const { status } = await api('PUT', `/api/contacts/${created.eid}`, { status: 'archived' });
    assert.equal(status, 200);
  });

  it('archived → active succeeds', async () => {
    const created = await createContact();
    await api('PUT', `/api/contacts/${created.eid}`, { status: 'archived' });
    const { status } = await api('PUT', `/api/contacts/${created.eid}`, { status: 'active' });
    assert.equal(status, 200);
  });

  it('archived → inactive rejects', async () => {
    const created = await createContact();
    await api('PUT', `/api/contacts/${created.eid}`, { status: 'archived' });
    const { status } = await api('PUT', `/api/contacts/${created.eid}`, { status: 'inactive' });
    assert.equal(status, 400);
  });

});

describe('cascade: note → contact', () => {
  it('deleting contact removes its notes', async () => {
    const parent = await createContact();
    await createNote({ 'contact': Number(parent.eid) });
    await api('DELETE', `/api/contacts/${parent.eid}`);
    const { data } = await api('GET', '/api/notes');
    const orphaned = data.filter(r => r['contact'] === Number(parent.eid));
    assert.equal(orphaned.length, 0);
  });
});

